# Ququ Voice Input - Windows Installation Script
# This script installs all dependencies and sets up the application

param(
    [switch]$SkipPython,
    [switch]$SkipNode,
    [switch]$NoStartup,
    [switch]$Help
)

if ($Help) {
    Write-Host "Ququ Voice Input Installation Script"
    Write-Host ""
    Write-Host "Usage: .\install-windows.ps1 [options]"
    Write-Host ""
    Write-Host "Options:"
    Write-Host "  -SkipPython    Skip Python installation check"
    Write-Host "  -SkipNode      Skip Node.js installation check"
    Write-Host "  -NoStartup     Don't configure auto-startup"
    Write-Host "  -Help          Show this help message"
    Write-Host ""
    exit 0
}

# Function to check if running as administrator
function Test-Administrator {
    $currentUser = [Security.Principal.WindowsIdentity]::GetCurrent()
    $principal = New-Object Security.Principal.WindowsPrincipal($currentUser)
    return $principal.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
}

# Function to install Chocolatey if not present
function Install-Chocolatey {
    if (!(Get-Command choco -ErrorAction SilentlyContinue)) {
        Write-Host "Installing Chocolatey..." -ForegroundColor Yellow
        Set-ExecutionPolicy Bypass -Scope Process -Force
        [System.Net.ServicePointManager]::SecurityProtocol = [System.Net.ServicePointManager]::SecurityProtocol -bor 3072
        iex ((New-Object System.Net.WebClient).DownloadString('https://community.chocolatey.org/install.ps1'))

        if (!(Get-Command choco -ErrorAction SilentlyContinue)) {
            Write-Host "Failed to install Chocolatey. Please install manually." -ForegroundColor Red
            exit 1
        }
        Write-Host "Chocolatey installed successfully!" -ForegroundColor Green
    } else {
        Write-Host "Chocolatey is already installed." -ForegroundColor Green
    }
}

# Function to check Python installation
function Test-Python {
    if ($SkipPython) {
        Write-Host "Skipping Python check..." -ForegroundColor Yellow
        return $true
    }

    $pythonVersion = $null
    try {
        $pythonVersion = python --version 2>&1
        if ($pythonVersion -match "Python (\d+)\.(\d+)") {
            $major = [int]$matches[1]
            $minor = [int]$matches[2]
            if ($major -eq 3 -and $minor -ge 8) {
                Write-Host "Python $($matches[0]) is installed." -ForegroundColor Green
                return $true
            }
        }
    } catch {}

    Write-Host "Python 3.8+ is required but not found." -ForegroundColor Red
    Write-Host "Installing Python..." -ForegroundColor Yellow

    choco install python -y
    refreshenv

    # Verify installation
    try {
        $pythonVersion = python --version 2>&1
        Write-Host "Python installed: $pythonVersion" -ForegroundColor Green
        return $true
    } catch {
        Write-Host "Failed to install Python. Please install manually." -ForegroundColor Red
        return $false
    }
}

# Function to check Node.js installation
function Test-NodeJS {
    if ($SkipNode) {
        Write-Host "Skipping Node.js check..." -ForegroundColor Yellow
        return $true
    }

    $nodeVersion = $null
    try {
        $nodeVersion = node --version 2>&1
        if ($nodeVersion -match "v(\d+)\.(\d+)") {
            $major = [int]$matches[1]
            if ($major -ge 16) {
                Write-Host "Node.js $nodeVersion is installed." -ForegroundColor Green
                return $true
            }
        }
    } catch {}

    Write-Host "Node.js 16+ is required but not found." -ForegroundColor Red
    Write-Host "Installing Node.js..." -ForegroundColor Yellow

    choco install nodejs -y
    refreshenv

    # Verify installation
    try {
        $nodeVersion = node --version 2>&1
        Write-Host "Node.js installed: $nodeVersion" -ForegroundColor Green
        return $true
    } catch {
        Write-Host "Failed to install Node.js. Please install manually." -ForegroundColor Red
        return $false
    }
}

# Function to install Python dependencies
function Install-PythonDeps {
    Write-Host "Installing Python dependencies..." -ForegroundColor Yellow

    $requirements = @(
        "fastapi",
        "uvicorn[standard]",
        "python-multipart",
        "funasr",
        "modelscope",
        "torch",
        "torchaudio"
    )

    foreach ($package in $requirements) {
        Write-Host "Installing $package..." -ForegroundColor Cyan
        pip install $package
        if ($LASTEXITCODE -ne 0) {
            Write-Host "Failed to install $package" -ForegroundColor Red
            return $false
        }
    }

    Write-Host "Python dependencies installed successfully!" -ForegroundColor Green
    return $true
}

# Function to install Node.js dependencies
function Install-NodeDeps {
    Write-Host "Installing Node.js dependencies..." -ForegroundColor Yellow

    if (!(Test-Path "package.json")) {
        Write-Host "package.json not found in current directory!" -ForegroundColor Red
        return $false
    }

    npm install
    if ($LASTEXITCODE -ne 0) {
        Write-Host "Failed to install Node.js dependencies" -ForegroundColor Red
        return $false
    }

    Write-Host "Node.js dependencies installed successfully!" -ForegroundColor Green
    return $true
}

# Function to create startup shortcut
function Set-Startup {
    if ($NoStartup) {
        Write-Host "Skipping startup configuration..." -ForegroundColor Yellow
        return
    }

    $currentDir = Get-Location
    $exePath = Join-Path $currentDir "node_modules\.bin\electron.cmd"
    $appPath = Join-Path $currentDir "main.js"

    # Create a batch file to start the application
    $batchContent = @"
@echo off
cd /d "$currentDir"
npm start
"@

    $batchPath = Join-Path $currentDir "ququ-startup.bat"
    $batchContent | Out-File -FilePath $batchPath -Encoding ASCII

    # Create shortcut in startup folder
    $shell = New-Object -ComObject WScript.Shell
    $startupPath = $shell.SpecialFolders("Startup")
    $shortcutPath = Join-Path $startupPath "Ququ Voice Input.lnk"

    $shortcut = $shell.CreateShortcut($shortcutPath)
    $shortcut.TargetPath = $batchPath
    $shortcut.WorkingDirectory = $currentDir
    $shortcut.Description = "Ququ Voice Input Tool"
    $shortcut.Save()

    Write-Host "Startup shortcut created: $shortcutPath" -ForegroundColor Green
}

# Function to create tray icon
function Create-TrayIcon {
    $iconDir = Join-Path (Get-Location) "assets"
    if (!(Test-Path $iconDir)) {
        New-Item -ItemType Directory -Path $iconDir -Force | Out-Null
    }

    # Create a simple tray icon (you might want to replace with a proper icon)
    $iconPath = Join-Path $iconDir "tray-icon.png"
    if (!(Test-Path $iconPath)) {
        # Create a simple placeholder icon
        Write-Host "Creating placeholder tray icon..." -ForegroundColor Yellow

        # This creates a simple 16x16 pixel PNG (base64 encoded minimal PNG)
        $iconData = ""
        [System.Convert]::FromBase64String($iconData) | Set-Content -Path $iconPath -Encoding Byte
    }
}

# Function to test ASR server
function Test-ASRServer {
    Write-Host "Testing ASR server connection..." -ForegroundColor Yellow

    try {
        # First check if server is running
        $response = Invoke-WebRequest -Uri "http://localhost:8000/health" -UseBasicParsing -TimeoutSec 5
        if ($response.StatusCode -eq 200) {
            Write-Host "ASR server is running and accessible!" -ForegroundColor Green
            return $true
        }
    } catch {
        Write-Host "ASR server not running. You can start it with: npm run asr:serve" -ForegroundColor Yellow
        return $false
    }
}

# Main installation process
Write-Host ""
Write-Host "============================================" -ForegroundColor Cyan
Write-Host "  Ququ Voice Input - Installation Script  " -ForegroundColor Cyan
Write-Host "============================================" -ForegroundColor Cyan
Write-Host ""

# Check if running as admin for Chocolatey
if (!(Test-Administrator)) {
    Write-Host "This script requires administrator privileges for installing dependencies." -ForegroundColor Yellow
    Write-Host "Please run PowerShell as Administrator and try again." -ForegroundColor Red
    Write-Host ""
    Write-Host "Note: You can skip dependency installation with -SkipPython and -SkipNode flags." -ForegroundColor Cyan
    exit 1
}

try {
    # Install Chocolatey
    Install-Chocolatey

    # Check and install Python
    if (!(Test-Python)) {
        Write-Host "Python installation failed!" -ForegroundColor Red
        exit 1
    }

    # Check and install Node.js
    if (!(Test-NodeJS)) {
        Write-Host "Node.js installation failed!" -ForegroundColor Red
        exit 1
    }

    # Install Python dependencies
    Write-Host ""
    Write-Host "Installing Python dependencies..." -ForegroundColor Yellow
    if (!(Install-PythonDeps)) {
        Write-Host "Python dependencies installation failed!" -ForegroundColor Red
        exit 1
    }

    # Install Node.js dependencies
    Write-Host ""
    Write-Host "Installing Node.js dependencies..." -ForegroundColor Yellow
    if (!(Install-NodeDeps)) {
        Write-Host "Node.js dependencies installation failed!" -ForegroundColor Red
        exit 1
    }

    # Create tray icon
    Create-TrayIcon

    # Set up startup
    Set-Startup

    # Test ASR server
    Write-Host ""
    Test-ASRServer

    Write-Host ""
    Write-Host "============================================" -ForegroundColor Green
    Write-Host "         Installation Completed!           " -ForegroundColor Green
    Write-Host "============================================" -ForegroundColor Green
    Write-Host ""
    Write-Host "Next steps:" -ForegroundColor Cyan
    Write-Host "1. Start the ASR server: npm run asr:serve" -ForegroundColor White
    Write-Host "2. Start the application: npm start" -ForegroundColor White
    Write-Host "3. Press F4 to start/stop recording" -ForegroundColor White
    Write-Host ""
    Write-Host "The application has been configured to start automatically with Windows." -ForegroundColor Green
    Write-Host ""

} catch {
    Write-Host "Installation failed: $($_.Exception.Message)" -ForegroundColor Red
    exit 1
}